parameters.jsCode:
const items = $input.all();

// Extract memories (looks for 'content' or 'raw_content' depending on how your Supabase RPC function returns it)
const memories = items
  .map(item => item.json.content || item.json.raw_content)
  .filter(c => c && c.trim() !== "")
  .join(' | ');

// Retrieve the current thought and the embedding vector to pass them to the AI and save them later
const currentThought = $('Merge Streams').item.json.final_thought;
const currentVector = $('Generate Embeddings').item.json.embedding.values;

return [{
  json: {
    final_thought: currentThought,
    historical_context: memories || "No previous history.",
    embedding_vector: currentVector
  }
}];

